import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

import java.util.Scanner;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Sanitize user input
        PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.LINKS);
        String sanitizedUserName = policy.sanitize(userName);

        System.out.println("Hello, " + sanitizedUserName + "!");

        // The following line will not execute as a script due to proper sanitization
        System.out.println("<script>alert('XSS Vulnerability')</script>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
